/// Field selection dialog for photo capture context
class _FieldSelectionDialog extends StatelessWidget {
  final Function(String) onFieldSelected;

  const _FieldSelectionDialog({
    required this.onFieldSelected,
  });

  @override
  Widget build(BuildContext context) {
    final fields = [
      'general',
      'defect_1',
      'defect_2',
      'before_repair',
      'after_repair',
      'equipment_id',
      'test_setup',
      'results',
    ];

    return AlertDialog(
      title: const Text('Select Photo Category'),
      content: SizedBox(
        width: double.maxFinite,
        child: ListView.builder(
          shrinkWrap: true,
          itemCount: fields.length,
          itemBuilder: (context, index) {
            final field = fields[index];
            return ListTile(
              title: Text(field.replaceAll('_', ' ').toUpperCase()),
              onTap: () => onFieldSelected(field),
            );
          },
        ),
      ),
      actions: [
        TextButton(
          onPressed: () => Navigator.of(context).pop(),
          child: const Text('Cancel'),
        ),
      ],
    );
  }
}
