  /// Reorder photos within the same pair (supports drag-and-drop)
  Future<void> reorderPhotosWithinPair(String? pairId, int oldIndex, int newIndex) async {
    if (oldIndex == newIndex) return;

    final pairPhotos = <PhotoFileInfo>[];
    for (final photo in _capturedPhotos) {
      if (_isSamePair(photo.photoPairId, pairId)) {
        pairPhotos.add(photo);
      }
    }

    if (pairPhotos.isEmpty ||
        oldIndex < 0 ||
        oldIndex >= pairPhotos.length ||
        newIndex < 0 ||
        newIndex >= pairPhotos.length) {
      return;
    }

    final updatedOrder = List<PhotoFileInfo>.from(pairPhotos);
    final moved = updatedOrder.removeAt(oldIndex);
    updatedOrder.insert(newIndex, moved);

