library;

import 'package:flutter/material.dart';
import '../models/photo.dart';
import '../services/photo_pair_manager.dart';

/// Badge overlay for photo thumbnails showing photo type
/// Colors: Overview (red), Close-up (blue), Additional (green)
class PhotoBadgeOverlay extends StatelessWidget {
  final PhotoType photoType;
  final double badgeSize;
  final Alignment alignment;

  const PhotoBadgeOverlay({
    super.key,
    required this.photoType,
    this.badgeSize = 60,
    this.alignment = Alignment.topRight,
  });

  @override
  Widget build(BuildContext context) {
    final color = PhotoPairManager.getBadgeColor(photoType);
