          ),
        ),
      ),
    );
  }
}

/// Dismissible photo card with badge overlay and swipe-to-delete
/// Implements AC-A.4.12 (swipe-to-delete with undo toast)
class PhotoCardWithBadge extends StatelessWidget {
  final String photoId;
  final String thumbnailPath;
  final PhotoType photoType;
  final VoidCallback onTap;
  final Function(String photoId) onDelete;
  final bool showBadge;

  const PhotoCardWithBadge({
    super.key,
    required this.photoId,
    required this.thumbnailPath,
    required this.photoType,
    required this.onTap,
    required this.onDelete,
    this.showBadge = true,
  });

  @override
  Widget build(BuildContext context) {
    return Dismissible(
      key: Key(photoId),
      direction: DismissDirection.endToStart,
      background: Container(
        alignment: Alignment.centerRight,
        padding: const EdgeInsets.only(right: 16),
        decoration: BoxDecoration(
          color: Colors.red,
          borderRadius: BorderRadius.circular(8),
        ),
        child: const Icon(
          Icons.delete,
          color: Colors.white,
          size: 32,
        ),
      ),
      confirmDismiss: (direction) async {
        // Show confirmation dialog (AC-A.4.7)
        return await showDialog<bool>(
          context: context,
          builder: (context) => AlertDialog(
            title: const Text('Delete Photo'),
            content: const Text('Delete this photo? This action cannot be undone.'),
            actions: [
              TextButton(
                onPressed: () => Navigator.of(context).pop(false),
                child: const Text('Cancel'),
              ),
              TextButton(
                onPressed: () => Navigator.of(context).pop(true),
                style: TextButton.styleFrom(foregroundColor: Colors.red),
                child: const Text('Delete'),
              ),
            ],
          ),
        );
      },
      onDismissed: (direction) {
        onDelete(photoId);

        // Show undo toast (AC-A.4.12: 3-second undo toast)
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: const Text('Photo deleted'),
            duration: const Duration(seconds: 3),
            action: SnackBarAction(
              label: 'Undo',
              onPressed: () {
                // TODO: Implement undo functionality
                // This would require storing the deleted photo temporarily
              },
            ),
          ),
        );
      },
      child: GestureDetector(
        onTap: onTap,
        child: Stack(
          fit: StackFit.expand,
          children: [
            // Photo thumbnail
            ClipRRect(
              borderRadius: BorderRadius.circular(8),
              child: Image.asset(
                thumbnailPath,
                fit: BoxFit.cover,
                errorBuilder: (context, error, stackTrace) {
                  return Container(
                    color: Colors.grey[300],
                    child: const Icon(Icons.broken_image, size: 48),
