{"output":"/// Photo Pair Manager - Enforces overview → close-up → additional workflow
/// Implements state machine for photo-pair capture sequence
library;

import 'dart:ui' show Color;
import 'package:flutter/foundation.dart';
import 'package:uuid/uuid.dart';
import '../models/photo.dart';

/// Photo pair capture state machine
/// Enforces AC-A.4.2: Overview → Close-up → Additional sequence
enum PhotoPairState {
  none,        // No photos captured yet
  overview,    // Overview photo captured, close-up enabled
  closeup,     // Close-up captured, additional enabled
  additional,  // Additional photo(s) captured, can capture more additional
}

/// Photo pair manager - Enforces photo-pair workflow
/// Manages state transitions and photo-pair ID generation
class PhotoPairManager extends ChangeNotifier {
  static const _uuid = Uuid();

  // Current state
  PhotoPairState _currentState = PhotoPairState.none;
  String? _currentPhotoPairId;

  // Photo counts for current pair
  int _overviewCount = 0;
  int _closeupCount = 0;
  int _additionalCount = 0;

  // Getters
  PhotoPairState get currentState => _currentState;
  String? get currentPhotoPairId => _currentPhotoPairId;
  int get overviewCount => _overviewCount;
  int get closeupCount => _closeupCount;
  int get additionalCount => _additionalCount;
  int get totalPhotosInPair => _overviewCount + _closeupCount + _additionalCount;

  /// Check if overview photo is allowed
  bool get canCaptureOverview =>
      _currentState == PhotoPairState.none ||
      _currentState == PhotoPairState.additional;

  /// Check if close-up photo is allowed (AC-A.4.2: UI blocks close-up until overview)
  bool get canCaptureCloseup =>
      _currentState == PhotoPairState.overview ||
      _currentState == PhotoPairState.closeup ||
      _currentState == PhotoPairState.additional;

  /// Check if additional photo is allowed
  bool get canCaptureAdditional =>
      _currentState == PhotoPairState.closeup ||
      _currentState == PhotoPairState.additional;

  /// Get current step number (1-3) for progress indicator (AC-A.4.3, AC-A.4.10)
  int get currentStep {
    switch (_currentState) {
      case PhotoPairState.none:
        return 1; // About to capture overview
      case PhotoPairState.overview:
        return 2; // About to capture close-up
      case PhotoPairState.closeup:
      case PhotoPairState.additional:
        return 3; // Capturing additional photos
    }
  }

  /// Get step description for UI (AC-A.4.3)
  String get stepDescription {
    switch (_currentState) {
      case PhotoPairState.none:
        return 'Step 1 of 3: Overview';
      case PhotoPairState.overview:
        return 'Step 2 of 3: Close-up';
      case PhotoPairState.closeup:
      case PhotoPairState.additional:
        return 'Step 3 of 3: Additional';
    }
  }

  /// Get progress fraction for progress ring (0.0 - 1.0)
  double get progress {
    switch (_currentState) {
      case PhotoPairState.none:
        return 0.0;
      case PhotoPairState.overview:
        return 0.33;
      case PhotoPairState.closeup:
        return 0.66;
      case PhotoPairState.additional:
        return 1.0;
    }
  }

  /// Start a new photo pair (generates new photo_pair_id)
  /// Called when capturing overview photo
  String startNewPhotoPair() {
    _currentPhotoPairId = _uuid.v4();
    _currentState = PhotoPairState.none;
    _overviewCount = 0;
    _closeupCount = 0;
    _additionalCount = 0;
    debugPrint('[PhotoPairManager] Started new photo pair: $_currentPhotoPairId');
    notifyListeners();
    return _currentPhotoPairId!;
  }

  /// Register photo capture and advance state machine
  /// Returns photo_pair_id for the captured photo
  /// Throws StateError if invalid transition
  String capturePhoto(PhotoType photoType) {
    // Ensure we have a photo pair ID
    _currentPhotoPairId ??= startNewPhotoPair();

    // Validate state transition
    switch (photoType) {
      case PhotoType.overview:
        if (!canCaptureOverview) {
          throw StateError(
            'Cannot capture overview from state $_currentState. '
            'Overview can only be captured when starting a new pair.',
          );
        }
        _overviewCount++;
        _currentState = PhotoPairState.overview;
        debugPrint('[PhotoPairManager] Captured overview (pair: $_currentPhotoPairId)');
        break;

      case PhotoType.closeup:
        if (!canCaptureCloseup) {
          throw StateError(
            'Cannot capture close-up from state $_currentState. '
            'Must capture overview first (AC-A.4.2).',
          );
        }
        _closeupCount++;
        _currentState = PhotoPairState.closeup;
        debugPrint('[PhotoPairManager] Captured close-up (pair: $_currentPhotoPairId)');
        break;

      case PhotoType.additional:
        if (!canCaptureAdditional) {
          throw StateError(
            'Cannot capture additional from state $_currentState. '
            'Must capture overview and close-up first.',
          );
        }
        _additionalCount++;
        _currentState = PhotoPairState.additional;
        debugPrint('[PhotoPairManager] Captured additional (pair: $_currentPhotoPairId)');
        break;
    }

    notifyListeners();
    return _currentPhotoPairId!;
  }

  /// Complete current photo pair and reset for next pair
  /// Called when user starts a new photo pair
  void completePhotoPair() {
    if (_currentState == PhotoPairState.none) {
      debugPrint('[PhotoPairManager] No active photo pair to complete');
      return;
    }

    debugPrint(
      '[PhotoPairManager] Completed photo pair $_currentPhotoPairId '
      '(overview: $_overviewCount, closeup: $_closeupCount, additional: $_additionalCount)',
    );

    // Reset state for new pair
    _currentPhotoPairId = null;
    _currentState = PhotoPairState.none;
    _overviewCount = 0;
    _closeupCount = 0;
    _additionalCount = 0;
    notifyListeners();
  }

  /// Reset manager to initial state
  void reset() {
    _currentPhotoPairId = null;
    _currentState = PhotoPairState.none;
    _overviewCount = 0;
    _closeupCount = 0;
    _additionalCount = 0;
    debugPrint('[PhotoPairManager] Reset to initial state');
    notifyListeners();
  }

  /// Get badge color for photo type (AC-A.4.11)
  static Color getBadgeColor(PhotoType photoType) {
    switch (photoType) {
      case PhotoType.overview:
        return const Color(0xFFE53935); // Red
      case PhotoType.closeup:
        return const Color(0xFF1E88E5); // Blue
      case PhotoType.additional:
        return const Color(0xFF43A047); // Green
    }
  }

  /// Get badge label text (AC-A.4.11)
  static String getBadgeLabel(PhotoType photoType) {
    switch (photoType) {
      case PhotoType.overview:
        return 'Overview';
      case PhotoType.closeup:
        return 'Close-up';
      case PhotoType.additional:
        return 'Additional';
    }
  }
}
