/// GPS coordinates for photo metadata (AC-A.4.4)
/// Nullable if location permission denied or unavailable
class GpsCoordinates {
  final double latitude;   // -90 to 90
  final double longitude;  // -180 to 180
  final double accuracy;   // meters

  GpsCoordinates({
    required this.latitude,
    required this.longitude,
    required this.accuracy,
  }) {
    // Validate latitude range (AC-A.4.4)
    if (latitude < -90 || latitude > 90) {
      throw RangeError.range(
        latitude,
        -90,
        90,
        'latitude',
        'Latitude must be between -90 and 90 degrees',
      );
    }

    // Validate longitude range (AC-A.4.4)
    if (longitude < -180 || longitude > 180) {
      throw RangeError.range(
        longitude,
        -180,
        180,
        'longitude',
        'Longitude must be between -180 and 180 degrees',
      );
    }

    // Validate accuracy is non-negative
    if (accuracy < 0) {
      throw RangeError(
        'Accuracy must be non-negative, got: $accuracy',
      );
    }
  }

  /// Validate GPS coordinates
  bool get isValid =>
      latitude >= -90 && latitude <= 90 &&
      longitude >= -180 && longitude <= 180 &&
      accuracy >= 0;

  Map<String, dynamic> toJson() => {
    'latitude': latitude,
    'longitude': longitude,
    'accuracy': accuracy,
  };

  factory GpsCoordinates.fromJson(Map<String, dynamic> json) => GpsCoordinates(
    latitude: (json['latitude'] as num).toDouble(),
    longitude: (json['longitude'] as num).toDouble(),
    accuracy: (json['accuracy'] as num).toDouble(),
  );

  factory GpsCoordinates.fromPosition(Position position) => GpsCoordinates(
    latitude: position.latitude,
    longitude: position.longitude,
    accuracy: position.accuracy,
  );
}

