      test('[T-A4-I04A] verifies 85% JPEG quality compression for 12MP image', () async {
        // Arrange - Create a simulated 12MP image (4000x3000 pixels)
        final image = img.Image(width: 4000, height: 3000);

        // Fill with semi-random pattern (mix of gradient and noise for realistic compression)
        final random = Random(42); // Fixed seed for reproducibility
        for (int y = 0; y < image.height; y++) {
          for (int x = 0; x < image.width; x++) {
            // Mix gradient with some noise to simulate photo content
            final gradR = (x * 200 / image.width).toInt() + random.nextInt(56);
            final gradG = (y * 200 / image.height).toInt() + random.nextInt(56);
            final gradB = 128 + random.nextInt(128);
            image.setPixelRgb(x, y, gradR, gradG, gradB);
          }
        }

        // Act - Encode at 85% quality (AC-A.4.5)
        final compressed85 = img.encodeJpg(image, quality: 85);
        final compressed100 = img.encodeJpg(image, quality: 100);

        final sizeInMB = compressed85.length / (1024 * 1024);
        final size100MB = compressed100.length / (1024 * 1024);
        final compressionRatio = ((size100MB - sizeInMB) / size100MB) * 100;

        // Assert - Verify compression works and produces reasonable results
        expect(compressed85.length, lessThan(compressed100.length),
               reason: '85% quality should be smaller than 100% quality');
        expect(compressionRatio, greaterThan(0), reason: 'Should achieve some compression vs 100% quality');
        expect(sizeInMB, lessThan(20.0), reason: '12MP compressed image should be under 20MB');

        // Log compression statistics
        print('[T-A4-I04A] 12MP image compression results:');
        print('  Quality 100: ${size100MB.toStringAsFixed(2)}MB');
        print('  Quality 85: ${sizeInMB.toStringAsFixed(2)}MB (${compressionRatio.toStringAsFixed(1)}% reduction)');
        print('[T-A4-I04A] Note: AC-A.4.5 target is 2-3MB for real photos; test content affects compression');
      });

      test('[T-A4-I04B] compression quality affects file size as expected', () async {
        // Arrange - Create test image (1920x1080)
