      fieldId: widget.fieldId,
      localPath: capturedPath,
      role: role == PhotoRole.overview ? 'overview' : 'closeup',
      exifData: exifData,
    );

    // Create Photo object with EXIF data
    final photo = Photo(
      id: photoId, // Use SQLite-generated ID
      role: role,
      localPath: capturedPath,
      exifData: exifData,
      capturedAt: DateTime.now(),
    );

    setState(() {
      if (role == PhotoRole.overview) {
        _overviewPhoto = photo;
      } else if (index != null) {
        _closeupPhotos[index] = photo;
      }
    });

    _notifyChanges();
  }

